mapper.select:
select ndgsg.*, ndg.*, #{status} as statusParam, #{shelfId} as shelfIdParam, ndgss.*, stockPurGoods.nx_distributer_purchase_goods_id as stockPurGoods_nx_distributer_purchase_goods_id, stockPurGoods.nx_DPG_finish_amount as stockPurGoods_nx_DPG_finish_amount, stockPurGoods.nx_DPG_dis_goods_id as stockPurGoods_nx_DPG_dis_goods_id, stockPurGoods.nx_DPG_dis_goods_father_id as stockPurGoods_nx_DPG_dis_goods_father_id, stockPurGoods.nx_DPG_dis_goods_grand_id as stockPurGoods_nx_DPG_dis_goods_grand_id, stockPurGoods.nx_DPG_nx_weight_id as stockPurGoods_nx_DPG_nx_weight_id, stockPurGoods.nx_DPG_batch_id as stockPurGoods_nx_DPG_batch_id, stockPurGoods.nx_DPG_quantity as stockPurGoods_nx_DPG_quantity, stockPurGoods.nx_DPG_buy_quantity as stockPurGoods_nx_DPG_buy_quantity, stockPurGoods.nx_DPG_buy_subtotal as stockPurGoods_nx_DPG_buy_subtotal, stockPurGoods.nx_DPG_standard as stockPurGoods_nx_DPG_standard, stockPurGoods.nx_DPG_status as stockPurGoods_nx_DPG_status, stockPurGoods.nx_DPG_buy_price as stockPurGoods_nx_DPG_buy_price, stockPurGoods.nx_DPG_purchase_type as stockPurGoods_nx_DPG_purchase_type, stockPurGoods.nx_DPG_orders_amount as stockPurGoods_nx_DPG_orders_amount, stockPurGoods.nx_DPG_type_add_user_id as stockPurGoods_nx_DPG_type_add_user_id, stockPurGoods.nx_DPG_input_type as stockPurGoods_nx_DPG_input_type, stockPurGoods.nx_DPG_time as stockPurGoods_nx_DPG_time, stockPurGoods.nx_DPG_purchase_date as stockPurGoods_nx_DPG_purchase_date, stockPurGoods.nx_DPG_distributer_id as stockPurGoods_nx_DPG_distributer_id, stockPurGoods.nx_DPG_sell_user_id as stockPurGoods_nx_DPG_sell_user_id, stockPurGoods.nx_DPG_buy_user_id as stockPurGoods_nx_DPG_buy_user_id, stockPurGoods.nx_DPG_pur_user_id as stockPurGoods_nx_DPG_pur_user_id, stockPurGoods.nx_DPG_cost_level as stockPurGoods_nx_DPG_cost_level, stockPurGoods.nx_DPG_pay_type as stockPurGoods_nx_DPG_pay_type, stockPurUser.nx_distributer_user_id as stockPurUser_nx_distributer_user_id, stockPurUser.nx_DIU_wx_nick_name as stockPurUser_nx_DIU_wx_nick_name, stockPurUser.nx_DIU_wx_avartra_url as stockPurUser_nx_DIU_wx_avartra_url, stockPurUser.nx_DIU_wx_open_id as stockPurUser_nx_DIU_wx_open_id, stockPurUser.nx_DIU_wx_phone as stockPurUser_nx_DIU_wx_phone, stockPurUser.nx_DIU_distributer_id as stockPurUser_nx_DIU_distributer_id, stockPurUser.nx_DIU_admin as stockPurUser_nx_DIU_admin from ( select ndgsg.nx_distributer_goods_shelf_goods_id from nx_distributer_goods_shelf_goods as ndgsg
and nx_DGSG_shelf_id = #{shelfId}
and nx_DGSG_sort > #{dayuSort}
and nx_DGSG_dis_goods_id = #{disGoodsId}
order by nx_DGSG_sort asc
limit #{offset}, #{limit}
) as t1 inner join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_distributer_goods_shelf_goods_id = t1.nx_distributer_goods_shelf_goods_id left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = ndgsg.nx_DGSG_dis_goods_id left join nx_distributer_goods_shelf_stock as ndgss on ndgss.nx_dgss_nx_shelf_goods_id = ndgsg.nx_distributer_goods_shelf_goods_id and ndgss.nx_dgss_rest_weight > 0 and ndgss.nx_dgss_status = 0 left join nx_distributer_purchase_goods as stockPurGoods on stockPurGoods.nx_distributer_purchase_goods_id = ndgss.nx_dgss_nx_pur_goods_id left join nx_distributer_user as stockPurUser on stockPurUser.nx_distributer_user_id = stockPurGoods.nx_DPG_pur_user_id order by ndgsg.nx_DGSG_sort asc

select ndpg.nx_distributer_purchase_goods_id, ndpg.nx_DPG_finish_amount, ndpg.nx_DPG_dis_goods_id, ndpg.nx_DPG_dis_goods_father_id, ndpg.nx_DPG_dis_goods_grand_id, ndpg.nx_DPG_nx_weight_id, ndpg.nx_DPG_batch_id, ndpg.nx_DPG_quantity, ndpg.nx_DPG_buy_quantity, ndpg.nx_DPG_buy_subtotal, ndpg.nx_DPG_standard, ndpg.nx_DPG_status, ndpg.nx_DPG_buy_price, ndpg.nx_DPG_purchase_type, ndpg.nx_DPG_orders_amount, ndpg.nx_DPG_type_add_user_id, ndpg.nx_DPG_input_type, ndpg.nx_DPG_time, ndpg.nx_DPG_purchase_date, ndpg.nx_DPG_distributer_id, ndpg.nx_DPG_sell_user_id, ndpg.nx_DPG_buy_user_id, ndpg.nx_DPG_pur_user_id, ndpg.nx_DPG_cost_level, ndpg.nx_DPG_pay_type from nx_distributer_purchase_goods as ndpg where ndpg.nx_DPG_dis_goods_id = #{disGoodsId} and ndpg.nx_DPG_purchase_type != -1 and ndpg.nx_DPG_status < #{status}
and ndpg.nx_DPG_apply_shelf_id = #{shelfId}
limit 1

select distinct ndgsg.*, ndg.*, ndpg.*,
${inventoryType} as inventoryTypeParam,
null as inventoryTypeParam,
'${inventoryDate}' as inventoryDateParam,
null as inventoryDateParam,
'${inventoryWeek}' as inventoryWeekParam,
null as inventoryWeekParam,
'${inventoryMonth}' as inventoryMonthParam,
null as inventoryMonthParam,
COALESCE(( select SUM(CAST(ndgss2.nx_dgss_rest_weight AS DECIMAL(10,1))) from nx_distributer_goods_shelf_stock as ndgss2 left join nx_distributer_goods_shelf_stock_reduce as ir2 on ir2.nx_dgssr_nx_stock_id = ndgss2.nx_distributer_goods_shelf_stock_id and ir2.nx_dgssr_type = 2
and ir2.nx_dgssr_date = #{inventoryDate}
and ir2.nx_dgssr_week = #{inventoryWeek}
and ir2.nx_dgssr_month = #{inventoryMonth}
where ndgss2.nx_dgss_nx_shelf_goods_id = ndgsg.nx_distributer_goods_shelf_goods_id and ndgss2.nx_dgss_rest_weight > 0 and ndgss2.nx_dgss_status = 0 and ir2.nx_distributer_goods_shelf_stock_reduce_id IS NULL ), 0) as totalRestWeight from nx_distributer_goods_shelf_goods as ndgsg left join nx_distributer_goods_shelf_stock as ndgss on ndgss.nx_dgss_nx_dis_goods_id = ndgsg.nx_DGSG_dis_goods_id and ndgss.nx_dgss_rest_weight > 0 and ndgss.nx_dgss_status = 0 and ndgss.nx_dgss_nx_shelf_goods_id = ndgsg.nx_distributer_goods_shelf_goods_id left join nx_distributer_goods_shelf_stock_reduce as ir on ir.nx_dgssr_nx_stock_id = ndgss.nx_distributer_goods_shelf_stock_id and ir.nx_dgssr_type = 2
and ir.nx_dgssr_date = #{inventoryDate}
and ir.nx_dgssr_week = #{inventoryWeek}
and ir.nx_dgssr_month = #{inventoryMonth}
left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = ndgsg.nx_DGSG_dis_goods_id left join nx_distributer_purchase_goods as ndpg on ndpg.nx_DPG_dis_goods_id = ndg.nx_distributer_goods_id and ndpg.nx_DPG_purchase_type = 0 and ndpg.nx_DPG_status < 3
and ndgsg.nx_DGSG_shelf_id = #{shelfId}
and ir.nx_distributer_goods_shelf_stock_reduce_id IS NULL
and exists ( select 1 from nx_distributer_goods_shelf_stock as ndgss3 left join nx_distributer_goods_shelf_stock_reduce as ir3 on ir3.nx_dgssr_nx_stock_id = ndgss3.nx_distributer_goods_shelf_stock_id and ir3.nx_dgssr_type = 2
and ir3.nx_dgssr_date = #{inventoryDate}
and ir3.nx_dgssr_week = #{inventoryWeek}
and ir3.nx_dgssr_month = #{inventoryMonth}
where ndgss3.nx_dgss_nx_shelf_goods_id = ndgsg.nx_distributer_goods_shelf_goods_id and ndgss3.nx_dgss_rest_weight > 0 and ndgss3.nx_dgss_status = 0 and ir3.nx_distributer_goods_shelf_stock_reduce_id IS NULL )
order by ndgsg.nx_DGSG_sort asc
limit #{offset}, #{limit}

select ndgss.*
from nx_distributer_goods_shelf_stock as ndgss
left join nx_distributer_goods_shelf_stock_reduce as ir on ir.nx_dgssr_nx_stock_id = ndgss.nx_distributer_goods_shelf_stock_id
    and ir.nx_dgssr_type = 2

        and ir.nx_dgssr_date = #{inventoryDate}


        and ir.nx_dgssr_week = #{inventoryWeek}


        and ir.nx_dgssr_month = #{inventoryMonth}

where ndgss.nx_dgss_nx_shelf_goods_id = #{shelfGoodsId}
    and ndgss.nx_dgss_rest_weight > 0
    and ndgss.nx_dgss_status = 0
    and ir.nx_distributer_goods_shelf_stock_reduce_id IS NULL
order by ndgss.nx_dgss_date ASC

select count(distinct ndgsg.nx_distributer_goods_shelf_goods_id)
from nx_distributer_goods_shelf_goods as ndgsg
left join nx_distributer_goods_shelf_stock as ndgss on ndgss.nx_dgss_nx_dis_goods_id = ndgsg.nx_DGSG_dis_goods_id
    and ndgss.nx_dgss_rest_weight > 0
    and ndgss.nx_dgss_status = 0
    and ndgss.nx_dgss_nx_shelf_goods_id = ndgsg.nx_distributer_goods_shelf_goods_id
left join nx_distributer_goods_shelf_stock_reduce as ir on ir.nx_dgssr_nx_stock_id = ndgss.nx_distributer_goods_shelf_stock_id
    and ir.nx_dgssr_type = 2

        and ir.nx_dgssr_date = #{inventoryDate}


        and ir.nx_dgssr_week = #{inventoryWeek}


        and ir.nx_dgssr_month = #{inventoryMonth}



        and ndgsg.nx_DGSG_shelf_id = #{shelfId}

    and ir.nx_distributer_goods_shelf_stock_reduce_id IS NULL

    and exists (
        select 1
        from nx_distributer_goods_shelf_stock as ndgss3
        left join nx_distributer_goods_shelf_stock_reduce as ir3 on ir3.nx_dgssr_nx_stock_id = ndgss3.nx_distributer_goods_shelf_stock_id
            and ir3.nx_dgssr_type = 2

                and ir3.nx_dgssr_date = #{inventoryDate}


                and ir3.nx_dgssr_week = #{inventoryWeek}


                and ir3.nx_dgssr_month = #{inventoryMonth}

        where ndgss3.nx_dgss_nx_shelf_goods_id = ndgsg.nx_distributer_goods_shelf_goods_id
            and ndgss3.nx_dgss_rest_weight > 0
            and ndgss3.nx_dgss_status = 0
            and ir3.nx_distributer_goods_shelf_stock_reduce_id IS NULL
    )

select count(*)
from nx_distributer_goods_shelf_goods as ndgsg


        and nx_DGSG_shelf_id = #{shelfId}


        and nx_DGSG_sort > #{dayuSort}


        and nx_DGSG_dis_goods_id = #{disGoodsId}

select ndgsg.*, ndg.*, #{status} as statusParam, #{shelfId} as shelfIdParam, ndgss.*, ntr.nx_trace_report_id as traceReport_nx_trace_report_id, ntr.nx_TR_batch_id as traceReport_nx_TR_batch_id, ntr.nx_TR_supplier_id as traceReport_nx_TR_supplier_id, ntr.nx_TR_supplier_name as traceReport_nx_TR_supplier_name, ntr.nx_TR_supplier_contact as traceReport_nx_TR_supplier_contact, ntr.nx_TR_purchase_date as traceReport_nx_TR_purchase_date, ntr.nx_TR_stock_in_date as traceReport_nx_TR_stock_in_date, ntr.nx_TR_valid_start_date as traceReport_nx_TR_valid_start_date, ntr.nx_TR_valid_end_date as traceReport_nx_TR_valid_end_date, ntr.nx_TR_report_type as traceReport_nx_TR_report_type, ntr.nx_TR_file_path as traceReport_nx_TR_file_path, ntr.nx_TR_file_paths as traceReport_nx_TR_file_paths, ntr.nx_TR_file_type as traceReport_nx_TR_file_type, ntr.nx_TR_distributer_id as traceReport_nx_TR_distributer_id, ntr.nx_TR_create_user_id as traceReport_nx_TR_create_user_id, ntr.nx_TR_create_time as traceReport_nx_TR_create_time, ntr.nx_TR_update_time as traceReport_nx_TR_update_time, ntr.nx_TR_remark as traceReport_nx_TR_remark, stockPurGoods.nx_distributer_purchase_goods_id as stockPurGoods_nx_distributer_purchase_goods_id, stockPurGoods.nx_DPG_finish_amount as stockPurGoods_nx_DPG_finish_amount, stockPurGoods.nx_DPG_dis_goods_id as stockPurGoods_nx_DPG_dis_goods_id, stockPurGoods.nx_DPG_dis_goods_father_id as stockPurGoods_nx_DPG_dis_goods_father_id, stockPurGoods.nx_DPG_dis_goods_grand_id as stockPurGoods_nx_DPG_dis_goods_grand_id, stockPurGoods.nx_DPG_nx_weight_id as stockPurGoods_nx_DPG_nx_weight_id, stockPurGoods.nx_DPG_batch_id as stockPurGoods_nx_DPG_batch_id, stockPurGoods.nx_DPG_quantity as stockPurGoods_nx_DPG_quantity, stockPurGoods.nx_DPG_buy_quantity as stockPurGoods_nx_DPG_buy_quantity, stockPurGoods.nx_DPG_buy_subtotal as stockPurGoods_nx_DPG_buy_subtotal, stockPurGoods.nx_DPG_standard as stockPurGoods_nx_DPG_standard, stockPurGoods.nx_DPG_status as stockPurGoods_nx_DPG_status, stockPurGoods.nx_DPG_buy_price as stockPurGoods_nx_DPG_buy_price, stockPurGoods.nx_DPG_purchase_type as stockPurGoods_nx_DPG_purchase_type, stockPurGoods.nx_DPG_orders_amount as stockPurGoods_nx_DPG_orders_amount, stockPurGoods.nx_DPG_type_add_user_id as stockPurGoods_nx_DPG_type_add_user_id, stockPurGoods.nx_DPG_input_type as stockPurGoods_nx_DPG_input_type, stockPurGoods.nx_DPG_time as stockPurGoods_nx_DPG_time, stockPurGoods.nx_DPG_purchase_date as stockPurGoods_nx_DPG_purchase_date, stockPurGoods.nx_DPG_distributer_id as stockPurGoods_nx_DPG_distributer_id, stockPurGoods.nx_DPG_sell_user_id as stockPurGoods_nx_DPG_sell_user_id, stockPurGoods.nx_DPG_buy_user_id as stockPurGoods_nx_DPG_buy_user_id, stockPurGoods.nx_DPG_pur_user_id as stockPurGoods_nx_DPG_pur_user_id, stockPurGoods.nx_DPG_cost_level as stockPurGoods_nx_DPG_cost_level, stockPurGoods.nx_DPG_pay_type as stockPurGoods_nx_DPG_pay_type, stockPurUser.nx_distributer_user_id as stockPurUser_nx_distributer_user_id, stockPurUser.nx_DIU_wx_nick_name as stockPurUser_nx_DIU_wx_nick_name, stockPurUser.nx_DIU_wx_avartra_url as stockPurUser_nx_DIU_wx_avartra_url, stockPurUser.nx_DIU_wx_open_id as stockPurUser_nx_DIU_wx_open_id, stockPurUser.nx_DIU_wx_phone as stockPurUser_nx_DIU_wx_phone, stockPurUser.nx_DIU_distributer_id as stockPurUser_nx_DIU_distributer_id, stockPurUser.nx_DIU_admin as stockPurUser_nx_DIU_admin from ( select ndgsg.nx_distributer_goods_shelf_goods_id from nx_distributer_goods_shelf_goods as ndgsg
and nx_DGSG_shelf_id = #{shelfId}
and nx_DGSG_sort > #{dayuSort}
and nx_DGSG_dis_goods_id = #{disGoodsId}
order by nx_DGSG_sort asc
limit #{offset}, #{limit}
) as t1 inner join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_distributer_goods_shelf_goods_id = t1.nx_distributer_goods_shelf_goods_id left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = ndgsg.nx_DGSG_dis_goods_id left join nx_distributer_goods_shelf_stock as ndgss on ndgss.nx_dgss_nx_shelf_goods_id = ndgsg.nx_distributer_goods_shelf_goods_id and ndgss.nx_dgss_rest_weight > 0 and ndgss.nx_dgss_status = 0 left join nx_distributer_purchase_goods as stockPurGoods on stockPurGoods.nx_distributer_purchase_goods_id = ndgss.nx_dgss_nx_pur_goods_id left join nx_distributer_user as stockPurUser on stockPurUser.nx_distributer_user_id = stockPurGoods.nx_DPG_pur_user_id left join nx_trace_report as ntr on ntr.nx_trace_report_id = ndgss.nx_dgss_trace_report_id order by ndgsg.nx_DGSG_sort asc

select count(*)
from nx_distributer_goods_shelf_goods as ndgsg


        and nx_DGSG_shelf_id = #{shelfId}


        and nx_DGSG_sort > #{dayuSort}


        and nx_DGSG_dis_goods_id = #{disGoodsId}

select COUNT(DISTINCT ndgsg.nx_distributer_goods_shelf_goods_id)
from nx_distributer_goods_shelf_goods as ndgsg
inner join nx_department_orders as dor on dor.nx_DO_dis_goods_id = ndgsg.nx_DGSG_dis_goods_id


        and ndgsg.nx_DGSG_dis_goods_id is null


        and ndgsg.nx_DGSG_dis_goods_id is not null


        and dor.nx_DO_distributer_id = #{disId}


        and dor.nx_DO_status < #{status}


        and dor.nx_DO_purchase_status < #{purStatus}

select * from ( select distinct ndgsg.nx_distributer_goods_shelf_goods_id, ndgsg.nx_DGSG_shelf_sort, ndgsg.nx_DGSG_sort from nx_distributer_goods_shelf_goods as ndgsg inner join nx_department_orders as dor on dor.nx_DO_dis_goods_id = ndgsg.nx_DGSG_dis_goods_id
and ndgsg.nx_DGSG_shelf_id = #{shelfId}
and dor.nx_DO_distributer_id = #{disId}
and dor.nx_DO_status < #{status}
and dor.nx_DO_purchase_status < #{purStatus}
order by ndgsg.nx_DGSG_shelf_sort, ndgsg.nx_DGSG_sort
limit #{offset}, #{limit}
) as t1 inner join nx_distributer_goods_shelf_goods as ndgsg on ndgsg.nx_distributer_goods_shelf_goods_id = t1.nx_distributer_goods_shelf_goods_id inner join nx_department_orders as dor on dor.nx_DO_dis_goods_id = ndgsg.nx_DGSG_dis_goods_id left join nx_department as nds on nds.nx_department_id = dor.nx_DO_department_id left join nx_department as ndf on ndf.nx_department_id = nds.nx_department_father_id left join gb_department as ngds on ngds.gb_department_id = dor.nx_DO_gb_department_id left join gb_department as ngdf on ngdf.gb_department_id = dor.nx_DO_gb_department_father_id left join nx_restraunt as ndnr on ndnr.nx_restraunt_id = dor.nx_DO_nx_comm_restraunt_id left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = dor.nx_DO_dis_goods_id left join nx_distributer_goods_shelf_stock as ndgss on ndgss.nx_dgss_nx_dis_goods_id = ndg.nx_distributer_goods_id left join nx_department_dis_goods as nddg on nddg.nx_DDG_dis_goods_id = ndg.nx_distributer_goods_id and nddg.nx_DDG_gb_department_id = dor.nx_DO_gb_department_id order by t1.nx_DGSG_shelf_sort, t1.nx_DGSG_sort

select * from nx_distributer_goods_shelf_goods 
where nx_DGSG_dis_goods_id = #{disGoodsId} and nx_DGSG_shelf_id = #{shelfId}
limit 1

